        """
        enhanced = basic_result.copy()

        # Extract shared data
        shared_following = [
            item["value"] for item in basic_result.get("shared_interests", [])
            if item["type"] == "following"
        ]
        shared_topics = [
            item["value"] for item in basic_result.get("shared_interests", [])
            if item["type"] == "topic"
        ]

